// Unit test for computeWindAlert — verifies the strict gusts > threshold rule
// for both branches (alert and no-alert) with correct echoed fields and a
// non-empty human-readable message.
async function testComputeWindAlert() {
  // Branch 1: gusts ABOVE the threshold -> alert true
  const high = functions.call('computeWindAlert', { windGusts: 32.1 }, 25);
  assertEquals(high.alert, true, 'Gusts above threshold should trigger an alert');
  assertEquals(high.gusts, 32.1, 'Should echo the gust value');
  assertEquals(high.threshold, 25, 'Should echo the threshold');
  assert(typeof high.message === 'string' && high.message.length > 0, 'Alert message should be non-empty');
  assert(high.message.indexOf('exceed') >= 0, 'Alert message should describe exceeding the threshold');

  // Branch 2: gusts BELOW the threshold -> alert false
  const low = functions.call('computeWindAlert', { windGusts: 12.4 }, 25);
  assertEquals(low.alert, false, 'Gusts below threshold should not trigger an alert');
  assertEquals(low.gusts, 12.4, 'Should echo the gust value');
  assertEquals(low.threshold, 25, 'Should echo the threshold');
  assert(typeof low.message === 'string' && low.message.length > 0, 'No-alert message should be non-empty');
  assert(low.message.indexOf('within') >= 0, 'No-alert message should describe being within the threshold');

  // Edge case: exactly equal to the threshold is NOT an alert (strict >)
  const equal = functions.call('computeWindAlert', { windGusts: 25 }, 25);
  assertEquals(equal.alert, false, 'Gusts exactly at threshold should not alert (strictly greater)');
}
